/* json: error-path boundary KAT
 * Proves three safety fences fire on bad input:
 *   (A) JSON_E_FULL  -- 257-element array exceeds 256-item scratch cap
 *   (B) JSON_E_DEPTH -- object nested 65 levels exceeds JSON_MAX_DEPTH (64)
 *   (C) JSON_E_PARSE -- trailing garbage after valid value
 * Return 99 = all three fences fired correctly.
 */
module corpus_f55

extern @abi(c-msvc-x64) fn malloc(n: u64) -> *u8 from "msvcrt"
extern @abi(c-msvc-x64) fn free(p: *u8) -> u64 from "msvcrt"
extern @abi(c-msvc-x64) fn arena_new(bytes: u64) -> u64 from "arena.iii"
extern @abi(c-msvc-x64) fn arena_drop(id: u64) -> i32 from "arena.iii"
extern @abi(c-msvc-x64) fn json_parse(arena: u64, base: u64, len: u64) -> u64 from "json.iii"
extern @abi(c-msvc-x64) fn json_last_error() -> i32 from "json.iii"

/* JSON_E_FULL = -2 (array > 256 elements) */
const J_E_FULL  : i32 = -2i32
/* JSON_E_DEPTH = -4 (nesting > 64) */
const J_E_DEPTH : i32 = -4i32
/* JSON_E_PARSE = -3 (malformed / trailing garbage) */
const J_E_PARSE : i32 = -3i32

/* Build "[1,1,...,1]" with `count` elements.
 * Each element is "1" (1 byte); separators are "," (1 byte); brackets 2 bytes.
 * Total = 2 + count + (count - 1) = 2*count + 1 bytes. */
fn build_array(buf: *u8, count: u64) -> u64 {
    let mut pos : u64 = 0u64
    buf[pos] = 91u8   /* [ */
    pos = pos + 1u64
    let mut i : u64 = 0u64
    while i < count {
        if i > 0u64 {
            buf[pos] = 44u8   /* , */
            pos = pos + 1u64
        }
        buf[pos] = 49u8   /* 1 */
        pos = pos + 1u64
        i = i + 1u64
    }
    buf[pos] = 93u8   /* ] */
    pos = pos + 1u64
    return pos
}

/* Build `depth` levels of nested empty-object open braces: "{{{..."
 * then close all: "...}}}".
 * depth=65 means: open 65 times, then close 65 times.
 * Size = 2 * depth bytes. */
fn build_nested_obj(buf: *u8, depth: u64) -> u64 {
    let mut i : u64 = 0u64
    while i < depth {
        buf[i] = 123u8   /* { */
        i = i + 1u64
    }
    let mut j : u64 = 0u64
    while j < depth {
        buf[depth + j] = 125u8   /* } */
        j = j + 1u64
    }
    return depth * 2u64
}

fn main() -> u64 {
    let a : u64 = arena_new(1u64 << 20u64)

    /* --- (A) 257-element array must return JSON_INVALID + JSON_E_FULL --- */
    /* Size for 257 elements: 2*257+1 = 515 bytes */
    let arr_buf : *u8 = malloc(520u64)
    let arr_len : u64 = build_array(arr_buf, 257u64)
    let r_full : u64 = json_parse(a, arr_buf as u64, arr_len)
    if r_full != 0u64 { return 1u64 }          /* must be INVALID */
    if json_last_error() != J_E_FULL { return 2u64 }  /* must be E_FULL */

    /* Positive control: 256-element array must SUCCEED */
    let arr256_len : u64 = build_array(arr_buf, 256u64)
    let r_ok : u64 = json_parse(a, arr_buf as u64, arr256_len)
    if r_ok == 0u64 { return 3u64 }            /* 256 elements must parse */
    free(arr_buf)

    /* --- (B) 65-level nesting must return JSON_INVALID + JSON_E_DEPTH --- */
    /* Size: 2*65 = 130 bytes */
    let dep_buf : *u8 = malloc(136u64)
    let dep_len : u64 = build_nested_obj(dep_buf, 65u64)
    let r_dep : u64 = json_parse(a, dep_buf as u64, dep_len)
    if r_dep != 0u64 { return 4u64 }           /* must be INVALID */
    if json_last_error() != J_E_DEPTH { return 5u64 }  /* must be E_DEPTH */

    /* Positive control: 64-level nesting must SUCCEED */
    let dep64_len : u64 = build_nested_obj(dep_buf, 64u64)
    let r_dep64 : u64 = json_parse(a, dep_buf as u64, dep64_len)
    if r_dep64 == 0u64 { return 6u64 }         /* 64 levels must parse */
    free(dep_buf)

    /* --- (C) trailing garbage must return JSON_INVALID + JSON_E_PARSE --- */
    /* Input: "42 " (number followed by space then extra digit) */
    let tg_buf : *u8 = malloc(8u64)
    tg_buf[0] = 52u8    /* 4 */
    tg_buf[1] = 50u8    /* 2 */
    tg_buf[2] = 32u8    /* space (ws -- skipped by trailing ws check) */
    tg_buf[3] = 49u8    /* 1  <-- trailing garbage char after ws */
    let r_tg : u64 = json_parse(a, tg_buf as u64, 4u64)
    if r_tg != 0u64 { return 7u64 }            /* must be INVALID */
    if json_last_error() != J_E_PARSE { return 8u64 }  /* must be E_PARSE */
    free(tg_buf)

    arena_drop(a)
    return 99u64
}
